INSERT INTO `inspiration_library` (`id`, `tenant_id`, `title`, `author_name`, `author_url`, `sort_order`, `images`, `description`, `prompt_content`, `remark`, `created_at`, `updated_at`, `category_id`, `likes`, `views`, `model`) VALUES
(4, 1, '2005 年索尼 CyberShot 商场美食广场快照提示', '@Marky @ Easy-Peasy.AI', 'http://www.baidu.com', 0, '[\"https:\\/\\/saasshanghai.oss-cn-shanghai.aliyuncs.com\\/inspiration_assets\\/20260105\\/img_695b46cba06440.54342429.jpg\",\"https:\\/\\/saasshanghai.oss-cn-shanghai.aliyuncs.com\\/inspiration_assets\\/20260105\\/img_695b46cf27e489.69656681.jpg\"]', '一个图片提示，用青少年、刺眼的闪光灯、日期戳和 Myspace 时代的审美，重现一张早期数码相机拍摄的商场美食广场照片。', '一张 2005 年索尼 CyberShot 拍摄的低分辨率数码照片。一群青少年在购物中心美食广场闲逛。刺眼的机载闪光灯，高光略微过曝，阴影处有数字噪点。由于早期的数字处理，皮肤纹理看起来略显蜡质。右下角有一个橙色日期戳，显示为“{argument name=\"date stamp in english\" default=\"04/12/2005\"}”。抓拍，角度笨拙，具有 Myspace 照片美学。', '', '2026-01-05 13:07:10', '2026-01-06 15:49:24', 1, 0, 0, 'nano banana pro'),
(5, 1, '江户时代浮世绘风格的现代场景再现', '@VoxcatAI', '', 0, '[\"https:\\/\\/saasshanghai.oss-cn-shanghai.aliyuncs.com\\/inspiration_assets\\/20260105\\/img_695b5bddc56380.88297361.jpg\"]', '一个高度结构化的图像提示，用于描绘一个被重新构想为江户时代日本浮世绘木版画的现代场景，并详细指导如何处理时代错位的科技、构图、纹理和色彩。', '一幅日本江户时代的浮世绘木版画。整体感觉是葛饰北斋和歌川广重等大师的超现实合作，通过古老的视角重新构想现代科技。\n\n**场景：** {argument name=\"modern scene\" default=\"繁忙的涩谷十字路口\"}\n\n**江户时代转换逻辑：**\n人物身着江户时代的和服，但进行着现代活动。所有科技都被转化为超现实的江户时代等效物：\n* 智能手机是发光的、精心绘制的纸质卷轴，人们正聚精会神地阅读。\n* 地铁站和火车是巨大的铰接式木制蜈蚣车厢，在人群中穿梭。\n* 摩天大楼被重新构想成无尽的、高耸入云的木制宝塔，直插戏剧性的云层。\n* 机器人和机甲则以巨大的、身披盔甲的木版傀儡形象出现。\n\n构图采用扁平透视，带有粗大、醒目的手刻墨线轮廓。背景是高度风格化的浮世绘波浪图案和戏剧性的漩涡状云朵，远处地平线上可见富士山。\n\n图像必须看起来像一幅实物版画，而非数字绘画。\n* 纹理：整个作品中都有清晰可见的木纹纹理和粗糙的纸纤维。\n* 印刷缺陷：颜料渗色明显。模拟手工压制版画，带有轻微的颜色错位，以增加真实感。\n* 色彩调色板：严格限于传统的矿物颜料，主要使用普鲁士蓝、朱红色和柔和的赭黄色。\n* 光照：柔和、平坦、无阴影的光照，没有数字渐变。\n\n宽高比为 3:4 的竖向海报。包含描述场景的竖排日文书法，并在一个角落有一个传统的红色艺术家印章。', '', '2026-01-05 14:36:18', '2026-01-05 14:36:18', 1, 0, 0, 'seedream4.5'),
(6, 1, '黑神话悟空微缩模型', 'A', '', 0, '[\"https:\\/\\/saasshanghai.oss-cn-shanghai.aliyuncs.com\\/inspiration_assets\\/20260105\\/img_695b6489d583b5.42920562.jpg\"]', 'A', '基于 [黑神话悟空] 中的 [单挑四大天王] 场景，创建一个超写实的等距视角微缩立体场景，悬浮在纯白背景之上。完整保留原始场景的氛围、比例关系与空间逻辑。底座材质尽可能与地面保持一致。使用 45 度等距视角，采用与原始画面一致的柔和自然日光，不包含天空与地平线。', '', '2026-01-05 15:10:39', '2026-01-05 15:13:15', 1, 0, 0, 'seedream4.5'),
(7, 1, '2025年度总结', '2025年度总结', '', 0, '[\"https:\\/\\/saasshanghai.oss-cn-shanghai.aliyuncs.com\\/inspiration_assets\\/20260106\\/img_695cf7f69e09c2.77695415.jpg\"]', '用以上图片生成2025年度总结，大量增加涂鸦手绘风格和美食风景元素。画面有主次之分，突出图6女孩的画面占比。', '用以上图片生成2025年度总结，大量增加涂鸦手绘风格和美食风景元素。画面有主次之分，突出图6女孩的画面占比。', '', '2026-01-06 19:54:40', '2026-01-06 19:54:40', 1, 0, 0, '');

