DROP TABLE IF EXISTS `model_configs`;
CREATE TABLE IF NOT EXISTS `model_configs` (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'Display Name',
  `model_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'Model Identifier',
  `model_identity` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '模型标识',
  `api_key` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'API Key',
  `endpoint` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'API Endpoint',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'active' COMMENT 'Status: active/inactive',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'Remark/Note',
  `create_time` int DEFAULT '0' COMMENT 'Create Time',
  `update_time` int DEFAULT '0' COMMENT 'Update Time',
  `delete_time` int DEFAULT NULL COMMENT 'Delete Time',
  `cost_per_request` int DEFAULT '1' COMMENT '单次请求消耗点数',
  `call_count` int DEFAULT '0' COMMENT '累计调用次数',
  `model_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'llm' COMMENT '模型类型: llm, image, video, audio',
  `points` int DEFAULT '1' COMMENT 'Points cost per call',
  `size_config` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '尺寸配置及价格(JSON)',
  `duration_config` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '时长配置及价格(JSON)',
  `quality_config` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '清晰度配置及价格(JSON)',
  `aspect_ratio_config` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '视频比例配置及价格(JSON)',
  `enable_first_frame` tinyint(1) DEFAULT '0' COMMENT '是否支持首帧',
  `enable_first_last_frame` tinyint(1) DEFAULT '0' COMMENT '是否支持首尾帧',
  `enable_multi_image_ref` tinyint(1) DEFAULT '0' COMMENT '是否支持多图参考',
  `enable_video_ref` tinyint(1) DEFAULT '0' COMMENT '是否支持视频参考',
  `resolution_config` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '分辨率配置及价格(JSON)',
  `provider_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'Provider code for routing',
  PRIMARY KEY (`id`),
  KEY `model_id` (`model_id`)
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Model Configurations';

