--
-- 表的结构 `orders`
--

DROP TABLE IF EXISTS `orders`;
CREATE TABLE IF NOT EXISTS `orders` (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `order_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Order Number',
  `tenant_id` int DEFAULT NULL COMMENT 'Tenant ID',
  `user_id` int DEFAULT NULL COMMENT 'User ID',
  `package_id` int DEFAULT NULL COMMENT 'Package ID',
  `amount` decimal(10,2) DEFAULT NULL COMMENT 'Order Amount',
  `payment_method` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Payment Method: wechat/alipay',
  `status` int DEFAULT '0' COMMENT 'Status: 0-Pending, 1-Paid, 2-Cancelled, 3-Refunded',
  `transaction_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Third-party Transaction ID',
  `pay_time` datetime DEFAULT NULL COMMENT 'Payment Time',
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `order_no` (`order_no`),
  KEY `tenant_id` (`tenant_id`,`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- 表的结构 `packages`
--

DROP TABLE IF EXISTS `packages`;
CREATE TABLE IF NOT EXISTS `packages` (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT 'Tenant ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Package Name',
  `price` decimal(10,2) DEFAULT NULL COMMENT 'Price',
  `duration_days` int DEFAULT '30' COMMENT 'Duration in days',
  `points` int DEFAULT '0' COMMENT 'Included points',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Description',
  `status` int DEFAULT '1' COMMENT 'Status: 0=Disabled, 1=Enabled',
  `create_time` datetime DEFAULT NULL COMMENT 'Create Time',
  `update_time` datetime DEFAULT NULL COMMENT 'Update Time',
  `delete_time` datetime DEFAULT NULL COMMENT 'Delete Time',
  `reset_cycle_days` int DEFAULT '0' COMMENT 'Points reset cycle in days (0=no reset)',
  `theme_color` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Theme Color (Hex)',
  `original_price` decimal(10,2) DEFAULT '0.00' COMMENT 'Original price for display',
  PRIMARY KEY (`id`),
  KEY `tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

