--
-- 表的结构 `saas_instances`
--

DROP TABLE IF EXISTS `saas_instances`;
CREATE TABLE IF NOT EXISTS `saas_instances` (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'Instance Name',
  `domain` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'Domain Name',
  `admin_email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'Admin Email',
  `password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'Login Password Hash',
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'Contact Phone',
  `status` int DEFAULT '1' COMMENT 'Status: 1=Active, 0=Suspended',
  `quota` int DEFAULT '0' COMMENT 'Resource Quota',
  `used` int DEFAULT '0' COMMENT 'Used Resources',
  `expiry_date` date DEFAULT NULL COMMENT 'Expiry Date',
  `create_time` int DEFAULT '0' COMMENT 'Create Time',
  `update_time` int DEFAULT '0' COMMENT 'Update Time',
  `home_config` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '主页配置JSON',
  `user_agreement` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '用户协议',
  `privacy_policy` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '隐私政策',
  `system_config` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '系统设置配置JSON',
  `sms_quota` int DEFAULT '0' COMMENT 'SMS quota',
  PRIMARY KEY (`id`),
  UNIQUE KEY `domain` (`domain`),
  KEY `name` (`name`)
) ENGINE=InnoDB AUTO_INCREMENT=89 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='SaaS Instances Table';

