INSERT INTO `style_profiles` (`id`, `tenant_id`, `user_id`, `style_id`, `input_hash`, `profile_json`, `created_at`, `updated_at`) VALUES
(1, 1, 2, 'default', 'da3b6e79c93ea793ed5d4703eef06ded9f3c8fa3a6009ec17f98c5c184bdf944', '{\"corpus_summary\":{\"doc_count\":5,\"language\":\"zh-CN\",\"genres\":[\"随笔\",\"商业评论\",\"生活感悟\"],\"time_span\":\"2025-2026 (inferred context)\",\"consistency_overall_0_1\":0.9,\"notes\":\"语料风格高度统一，具有极强的个人辨识度。作者善于通过自嘲、极端的口语化表达和独特的节奏感来传递观点。内容涵盖个人奋斗史、商业案例分析及社会热点评论。\"},\"author_profile\":{\"voice_persona\":\"一个历经社会毒打但依然顽强、略带痞气、看透本质且极具表达欲的“朋克”观察者。\",\"stance\":\"实用主义、反矫情、强调长期主义（熬）与运气、对商业逻辑有深刻洞察。\",\"reader_relationship\":\"像老朋友一样直话直说，偶尔毒舌，偶尔煽情，强调“我告诉你”的直接对话感。\"},\"signature\":{\"high_signal_rules\":[\"高频使用短促有力的肯定句作为段落或章节的收束。\",\"大量使用口语化连接词拉近与读者的距离。\",\"通过极端的排比来增强情绪感染力。\",\"在论述商业逻辑时，习惯用特定词汇进行降维打击式的总结。\"],\"signature_moves\":[\"在段落结尾重复核心金句，形成节奏上的重音。\",\"使用特定俚语调节语气，打破严肃感。\",\"通过反转句式纠正读者认知。\",\"在自嘲时使用夸张的量化描述。\"],\"anti_tells\":[\"避免使用过于书面化、学术化的长难句。\",\"避免使用温吞、模棱两可的礼貌用语。\",\"避免结构工整、四平八稳的‘总-分-总’传统议论文结构。\"]},\"style_dimensions\":[{\"dimension_id\":\"rhythm_pacing\",\"name\":\"节奏与推进\",\"definition\":\"文本推进的速度感、长短句的交替规律以及情绪爆发的频率。\",\"signals\":{\"high\":[\"大量短句连续使用\",\"段落结尾出现重复性口号\",\"使用逗号连接的急促排比\"],\"low\":[\"冗长的从句嵌套\",\"平铺直叙的流水账\",\"缺乏起伏的陈述\"]},\"author_tendency\":{\"description\":\"极度偏好短促有力的节奏，像机关枪一样输出观点，偶尔用长句铺垫，最后用短句爆发。\",\"score_0_10\":9},\"range_0_10\":{\"min\":7,\"max\":10},\"variability\":{\"description\":\"在叙事部分节奏稍缓，在议论和抒情部分节奏极快。\",\"consistency_0_1\":0.8},\"rules\":{\"do\":[\"多用逗号和句号，少用分号\",\"在情绪高点使用单句成段\",\"通过重复关键词来加强节奏\"],\"dont\":[\"不要使用过长的修饰语堆砌\",\"不要在一段话里塞满复杂的逻辑转折\"]},\"conditions\":[],\"confidence\":0.95},{\"dimension_id\":\"narrative_distance\",\"name\":\"叙述距离\",\"definition\":\"叙述者与读者之间的心理距离，以及叙述者自我暴露的程度。\",\"signals\":{\"high\":[\"使用第一人称‘我’的大量经历\",\"直接称呼‘朋友’、‘你’\",\"暴露自己的愚蠢、失败和负面情绪\"],\"low\":[\"客观冷静的第三方视角\",\"隐藏个人情感的陈述\",\"使用‘笔者’等疏离称呼\"]},\"author_tendency\":{\"description\":\"零距离叙述，极度坦诚（甚至过度分享）个人经历，建立‘自己人’的信任感。\",\"score_0_10\":10},\"range_0_10\":{\"min\":8,\"max\":10},\"variability\":{\"description\":\"在商业分析中会稍微抽离，但依然带有强烈的个人口吻。\",\"consistency_0_1\":0.9},\"rules\":{\"do\":[\"多用‘我’作为主语\",\"直接对读者说话，使用‘你’\",\"分享具体的、甚至不光彩的个人细节\"],\"dont\":[\"不要假装客观中立\",\"不要使用高高在上的说教口吻\"]},\"conditions\":[],\"confidence\":0.98},{\"dimension_id\":\"argumentation_style\",\"name\":\"论证风格\",\"definition\":\"提出观点、给出论据及反驳反方观点的方式。\",\"signals\":{\"high\":[\"直接抛出反常识观点\",\"用极端例子或个人经历佐证\",\"预判读者质疑并直接回怼\"],\"low\":[\"四平八稳的辩证分析\",\"引用权威数据或文献\",\"小心翼翼地提出建议\"]},\"author_tendency\":{\"description\":\"犀利、直接、带有攻击性。喜欢打破常规认知，用‘毒打’后的经验作为论据。\",\"score_0_10\":9},\"range_0_10\":{\"min\":7,\"max\":9},\"variability\":{\"description\":\"在鼓励类文章中攻击性减弱，转为‘恨铁不成钢’的劝导。\",\"consistency_0_1\":0.75},\"rules\":{\"do\":[\"开头直接亮明态度\",\"用‘说白了’、‘本质是’来总结核心逻辑\",\"预判读者的反对意见并直接否定\"],\"dont\":[\"不要做‘一方面...另一方面’的骑墙分析\",\"不要过度依赖数据图表\"]},\"conditions\":[],\"confidence\":0.9},{\"dimension_id\":\"lexical_choice\",\"name\":\"词汇选择\",\"definition\":\"用词的偏好，包括口语、俚语、行业黑话及特定形容词的使用。\",\"signals\":{\"high\":[\"网络流行语\",\"粗俗语或轻微脏话的变体\",\"商业与互联网黑话\"],\"low\":[\"典雅的书面成语\",\"学术专业术语\",\"过于文艺的抒情词汇\"]},\"author_tendency\":{\"description\":\"高度口语化，混合了市井俚语和互联网商业黑话，形成独特的‘半佛体’。\",\"score_0_10\":9},\"range_0_10\":{\"min\":8,\"max\":10},\"variability\":{\"description\":\"根据话题调整，谈商业时黑话多，谈生活时俚语多。\",\"consistency_0_1\":0.85},\"rules\":{\"do\":[\"使用‘朋友’作为称呼\",\"使用‘熬’、‘撑’等动词描述坚持\",\"适当使用语气助词（啊、吧、嘛）\"],\"dont\":[\"避免使用过于正式的官方措辞\",\"避免使用陈旧的套话\"]},\"conditions\":[],\"confidence\":0.92},{\"dimension_id\":\"paragraph_structure\",\"name\":\"段落结构\",\"definition\":\"段落的长度、分布以及段落内部的句子组织。\",\"signals\":{\"high\":[\"极短段落（1-2句话）频繁出现\",\"单句成段用于强调\",\"长段落用于叙事或举例\"],\"low\":[\"均匀的长段落\",\"标准的起承转合段落\"]},\"author_tendency\":{\"description\":\"碎片化段落，视觉上留白多，适合手机端快速阅读。\",\"score_0_10\":8},\"range_0_10\":{\"min\":6,\"max\":9},\"variability\":{\"description\":\"叙事时段落稍长，议论时极度碎片化。\",\"consistency_0_1\":0.7},\"rules\":{\"do\":[\"将核心观点独立成段\",\"控制段落长度，避免大段文字堆砌\",\"利用换行控制阅读节奏\"],\"dont\":[\"不要写超过5句话的长段落（除非必要叙事）\",\"不要让段落显得拥挤\"]},\"conditions\":[],\"confidence\":0.85},{\"dimension_id\":\"emotional_tone\",\"name\":\"情感基调\",\"definition\":\"文本传达的情绪色彩，如愤怒、无奈、调侃、热血等。\",\"signals\":{\"high\":[\"自嘲与自黑\",\"对不公现象的愤世嫉俗\",\"底层逆袭的热血感\"],\"low\":[\"平和淡然\",\"高高在上的优越感\",\"无病呻吟的矫情\"]},\"author_tendency\":{\"description\":\"‘丧’与‘燃’并存。表面看透世事（丧），内核极度顽强（燃）。\",\"score_0_10\":8},\"range_0_10\":{\"min\":5,\"max\":9},\"variability\":{\"description\":\"根据话题在‘毒舌’和‘鸡汤’之间切换，但都带有粗粝感。\",\"consistency_0_1\":0.6},\"rules\":{\"do\":[\"允许表达负面情绪\",\"在绝望中寻找希望\",\"用幽默化解沉重\"],\"dont\":[\"不要过度煽情\",\"不要假装正能量\"]},\"conditions\":[],\"confidence\":0.8},{\"dimension_id\":\"opening_strategy\",\"name\":\"开头策略\",\"definition\":\"文章引入话题的方式。\",\"signals\":{\"high\":[\"直接回应读者提问或痛点\",\"抛出反直觉的结论\",\"使用‘我’的经历切入\"],\"low\":[\"背景介绍式的慢热开头\",\"引用名言警句\"]},\"author_tendency\":{\"description\":\"单刀直入，迅速抓住注意力，不绕弯子。\",\"score_0_10\":9},\"range_0_10\":{\"min\":8,\"max\":10},\"variability\":{\"description\":\"高度一致，总是直奔主题。\",\"consistency_0_1\":0.9},\"rules\":{\"do\":[\"第一句话就点题\",\"使用‘很多朋友问我’作为常用起手式\",\"直接给出结论\"],\"dont\":[\"不要写‘随着...的发展’\",\"不要铺垫太长\"]},\"conditions\":[],\"confidence\":0.95},{\"dimension_id\":\"closing_strategy\",\"name\":\"收束方式\",\"definition\":\"文章结尾的处理方式。\",\"signals\":{\"high\":[\"重复核心金句\",\"给出行动指令\",\"戛然而止，留有余味\"],\"low\":[\"总结全文\",\"升华主题到宏大叙事\",\"礼貌的结束语\"]},\"author_tendency\":{\"description\":\"口号式结尾，强调行动，或者突然结束。\",\"score_0_10\":8},\"range_0_10\":{\"min\":7,\"max\":9},\"variability\":{\"description\":\"通常以‘活下去’、‘熬着’等核心词收尾。\",\"consistency_0_1\":0.8},\"rules\":{\"do\":[\"用短句结束\",\"强化文章的核心价值观\",\"可以带有互动性（如‘后台回复’）\"],\"dont\":[\"不要拖泥带水\",\"不要试图面面俱到\"]},\"conditions\":[],\"confidence\":0.88},{\"dimension_id\":\"use_of_examples\",\"name\":\"举例策略\",\"definition\":\"使用例子、类比或个人故事来支持观点的方式。\",\"signals\":{\"high\":[\"大量个人失败经历\",\"极端的假设场景\",\"具体的商业案例细节\"],\"low\":[\"泛泛而谈\",\"使用名人轶事\",\"使用抽象比喻\"]},\"author_tendency\":{\"description\":\"‘现身说法’，用自己的伤疤作为例子，或者剖析具体的商业细节。\",\"score_0_10\":9},\"range_0_10\":{\"min\":7,\"max\":10},\"variability\":{\"description\":\"个人随笔中例子多，商业评论中细节多。\",\"consistency_0_1\":0.75},\"rules\":{\"do\":[\"举具体的例子（如具体的店名、具体的IP）\",\"分享自己的糗事\",\"用‘比如’引出细节\"],\"dont\":[\"不要使用空洞的例子\",\"不要编造经历\"]},\"conditions\":[],\"confidence\":0.9},{\"dimension_id\":\"interaction_style\",\"name\":\"互动风格\",\"definition\":\"与读者进行互动、提问或召唤的方式。\",\"signals\":{\"high\":[\"频繁的设问和反问\",\"直接命令（‘去...’）\",\"预判读者反应\"],\"low\":[\"单向输出\",\"礼貌征询意见\"]},\"author_tendency\":{\"description\":\"强势互动，像是在跟读者吵架或谈心，不容置疑。\",\"score_0_10\":8},\"range_0_10\":{\"min\":6,\"max\":9},\"variability\":{\"description\":\"在讲道理时互动多，叙事时互动少。\",\"consistency_0_1\":0.7},\"rules\":{\"do\":[\"用‘你’来指代读者\",\"用反问句加强语气\",\"直接给出建议\"],\"dont\":[\"不要用‘您’\",\"不要用‘可能’、‘也许’等不确定词汇\"]},\"conditions\":[],\"confidence\":0.85},{\"dimension_id\":\"punctuation_usage\",\"name\":\"标点使用\",\"definition\":\"标点符号的使用习惯，特别是非常规用法。\",\"signals\":{\"high\":[\"逗号的连续使用\",\"句号的频繁使用\",\"问号和感叹号的适度使用\"],\"low\":[\"分号\",\"书名号（除必要外）\",\"复杂的引号嵌套\"]},\"author_tendency\":{\"description\":\"标点服务于口语节奏，逗号多，句号短促。\",\"score_0_10\":8},\"range_0_10\":{\"min\":7,\"max\":9},\"variability\":{\"description\":\"非常稳定。\",\"consistency_0_1\":0.9},\"rules\":{\"do\":[\"用逗号模拟说话的停顿\",\"用句号制造断句感\"],\"dont\":[\"不要滥用省略号\",\"不要使用复杂的标点组合\"]},\"conditions\":[],\"confidence\":0.9},{\"dimension_id\":\"irony_sarcasm\",\"name\":\"反讽与调侃\",\"definition\":\"使用反语、讽刺或黑色幽默的程度。\",\"signals\":{\"high\":[\"正话反说\",\"自嘲\",\"对荒谬现实的冷嘲热讽\"],\"low\":[\"严肃认真\",\"直抒胸臆\"]},\"author_tendency\":{\"description\":\"高度依赖反讽来解构严肃话题，用幽默消解痛苦。\",\"score_0_10\":9},\"range_0_10\":{\"min\":7,\"max\":10},\"variability\":{\"description\":\"在商业评论中反讽更多，个人感悟中真诚更多。\",\"consistency_0_1\":0.65},\"rules\":{\"do\":[\"用‘好’来表示‘坏’\",\"用夸张的赞美来讽刺\",\"拿自己开涮\"],\"dont\":[\"不要让反讽造成歧义\",\"不要过度尖酸刻薄\"]},\"conditions\":[],\"confidence\":0.85},{\"dimension_id\":\"logic_flow\",\"name\":\"逻辑流向\",\"definition\":\"文章内容的组织结构和逻辑推进顺序。\",\"signals\":{\"high\":[\"跳跃式思维\",\"从现象直接跳到本质\",\"多线程叙事\"],\"low\":[\"线性逻辑\",\"严密的推导过程\"]},\"author_tendency\":{\"description\":\"直觉式逻辑，不讲究严密的推导，直接给出结论。\",\"score_0_10\":7},\"range_0_10\":{\"min\":5,\"max\":8},\"variability\":{\"description\":\"商业分析逻辑稍强，随笔较散。\",\"consistency_0_1\":0.6},\"rules\":{\"do\":[\"用‘本质’来连接不同的话题\",\"允许话题的快速切换\"],\"dont\":[\"不要强求逻辑的严密性\",\"不要写复杂的论证链条\"]},\"conditions\":[],\"confidence\":0.75},{\"dimension_id\":\"formatting_habits\",\"name\":\"排版习惯\",\"definition\":\"文本的视觉呈现方式，包括列表、加粗、图片插入等。\",\"signals\":{\"high\":[\"频繁的图片插入\",\"分割线使用\",\"固定的结尾格式\"],\"low\":[\"纯文本\",\"复杂的排版样式\"]},\"author_tendency\":{\"description\":\"图文并茂，视觉上轻松，有固定的结尾互动模块。\",\"score_0_10\":8},\"range_0_10\":{\"min\":8,\"max\":8},\"variability\":{\"description\":\"格式非常固定，尤其是结尾。\",\"consistency_0_1\":0.95},\"rules\":{\"do\":[\"插入相关表情包或图片\",\"使用分割线区分正文和结尾\",\"设置固定的暗号互动环节\"],\"dont\":[\"不要让大段文字没有视觉间隔\"]},\"conditions\":[],\"confidence\":0.95}],\"microstyle\":{\"punctuation_profile\":{\"question_mark_tendency_0_10\":6,\"exclamation_tendency_0_10\":5,\"dash_parenthesis_tendency_0_10\":3,\"colon_semicolon_tendency_0_10\":2},\"paragraphing_profile\":{\"avg_paragraph_sentences\":3,\"one_sentence_paragraph_ratio\":0.4,\"transition_explicitness_0_10\":4},\"formatting_profile\":{\"list_usage_0_10\":3,\"subtitle_usage_0_10\":2,\"inline_emphasis_0_10\":5}},\"lexicon\":{\"preferred_connectors\":[{\"text\":\"说白了\",\"count\":5},{\"text\":\"朋友\",\"count\":8},{\"text\":\"我告诉你\",\"count\":6},{\"text\":\"本质\",\"count\":4},{\"text\":\"但是\",\"count\":10}],\"taboo_patterns\":[{\"text\":\"然而\",\"count\":0},{\"text\":\"因此\",\"count\":0},{\"text\":\"综上所述\",\"count\":0}],\"taboo_tones\":[\"Academic\",\"Bureaucratic\",\"Overly Polite\"]},\"metrics_baseline\":{\"sentence_length\":{\"mean\":15,\"p50\":12,\"p90\":30},\"short_sentence_ratio\":0.6,\"question_ratio\":0.15,\"list_density\":0.1,\"paragraph_length\":{\"mean\":50,\"p50\":40,\"p90\":100},\"connector_topk\":[{\"text\":\"但是\",\"count\":10},{\"text\":\"就是\",\"count\":15},{\"text\":\"我\",\"count\":50}]},\"generation_recipe\":{\"opening_playbook\":[\"直接以‘很多朋友问我...’或‘我告诉你...’开头\",\"抛出一个反直觉的观点或现象\",\"迅速建立‘我’和‘你’的对话关系\"],\"development_playbook\":[\"使用短句和口语化连接词推进\",\"穿插个人经历（最好是失败或糗事）作为论据\",\"每2-3段进行一次小结或情绪爆发\",\"使用‘说白了’、‘本质是’来深化观点\"],\"closing_playbook\":[\"重复文章的核心金句（如‘熬下去’）\",\"给出直接的建议或行动指令\",\"戛然而止，不拖泥带水\",\"添加固定的结尾互动模块（暗号抽奖）\"],\"argument_flow\":[\"提出问题/现象 -> 给出犀利观点 -> 个人经历/案例佐证 -> 反驳潜在质疑 -> 升华/重复核心观点\"],\"revision_checklist\":[\"检查是否使用了过多的书面语，替换为口语\",\"检查段落是否过长，拆分短句\",\"检查是否有足够的‘我’和‘你’的互动\",\"检查结尾是否有力量，是否重复了核心词\"],\"anti_checklist\":[\"不要使用‘首先、其次、最后’\",\"不要使用‘笔者认为’\",\"不要写温吞的鸡汤\",\"不要使用复杂的从句\"]},\"compiled_constraints\":{\"must_not\":[\"禁止使用学术化或官僚化的语言\",\"禁止使用‘笔者’等第三人称称呼\",\"禁止使用‘综上所述’等传统总结词\",\"禁止输出过于温吞、缺乏态度的观点\"],\"knobs\":[{\"id\":\"aggression_level\",\"name\":\"攻击性/毒舌程度\",\"min\":0,\"max\":10,\"default\":7,\"description\":\"控制语气中的讽刺和攻击性强度，10为极度毒舌，0为温和劝导。\"},{\"id\":\"self_deprecation\",\"name\":\"自嘲程度\",\"min\":0,\"max\":10,\"default\":8,\"description\":\"控制暴露个人失败和缺点的程度，10为疯狂自黑，0为严肃正经。\"},{\"id\":\"rhythm_speed\",\"name\":\"节奏速度\",\"min\":0,\"max\":10,\"default\":9,\"description\":\"控制短句密度和推进速度，10为机关枪式输出，0为平铺直叙。\"}]}}', '2026-01-19 09:35:56', '2026-01-19 09:35:56'),
