(3, 1, 1, 'default', '2c2131f86a5fd8ee460cb8d5e1aab72cf19a6630000516644e40a8845b8cd25f', '{\"corpus_summary\":{\"doc_count\":1,\"language\":\"zh\",\"genres\":[\"商业分析\",\"科技评论\"],\"time_span\":\"\",\"consistency_overall_0_1\":1,\"notes\":\"基于单篇文档分析，所有特征的一致性均为最高值。\"},\"author_profile\":{\"voice_persona\":\"一位擅长将复杂商业逻辑通俗化的科技商业观察者，以清晰的逻辑和生动的类比引导读者思考。\",\"stance\":\"技术乐观主义，倾向于从技术革新角度解读行业变革。\",\"reader_relationship\":\"引导者与解释者，通过设问和类比拉近与读者的距离，建立共同探索的对话感。\"},\"signature\":{\"high_signal_rules\":[\"使用\'大白话来说\'、\'怎么理解？\'等口语化表达来解释核心概念。\",\"通过\'切蛋糕\'等生活化类比来阐释抽象的商业逻辑。\",\"采用\'第一刀、第二刀\'等序列化比喻来描述演进过程。\",\"在关键转折点使用设问句，如\'这已经是完美了吗？\'，以引导叙事节奏。\"],\"signature_moves\":[\"开篇以具体新闻事件切入，迅速引出核心议题。\",\"在深入分析前，先回归并重新定义最基础的概念（如\'保险是什么？\'）。\",\"使用编号小标题（01, 02, 03）构建清晰的论述层次。\",\"结尾引用名人名言，升华主题并留下思考空间。\"],\"anti_tells\":[\"避免使用未经解释的专业术语，所有术语出现后必须伴随通俗化解释。\",\"避免堆砌形容词，不使用空泛的赞美或批评，而是通过数据和逻辑对比来支撑观点。\",\"避免在段落内部进行视角切换，保持每个段落论述焦点的单一性。\"]},\"style_dimensions\":[{\"dimension_id\":\"macro_opening\",\"name\":\"开头策略\",\"definition\":\"文章开篇引入主题的方式。\",\"signals\":{\"high\":[\"以具体新闻事件切入\"],\"low\":[\"宏大叙事开场\",\"直接抛出结论\"]},\"author_tendency\":{\"description\":\"倾向于用一个具体的、有时效性的新闻事件作为引子，直接点明文章要探讨的核心变化。\",\"score_0_10\":9},\"range_0_10\":{\"min\":9,\"max\":9},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"以一个具体的新闻事件或案例作为文章的开端。\",\"在开篇明确点出该事件可能带来的深远影响。\"],\"dont\":[\"避免使用宽泛、抽象的引言。\"]},\"templates\":[\"[具体事件]宣布，[事件核心内容]。[通俗化解释]。事情看着简单，但意义可能非常大。\"],\"conditions\":[],\"confidence\":0.9},{\"dimension_id\":\"macro_progression\",\"name\":\"推进方式\",\"definition\":\"文章主体内容的论证推进逻辑。\",\"signals\":{\"high\":[\"回归基础概念\",\"分阶段演进论述\"],\"low\":[\"多点发散\",\"循环论证\"]},\"author_tendency\":{\"description\":\"采用\'回归原点-分步演进-展望未来\'的线性推进结构，逻辑链条清晰。\",\"score_0_10\":10},\"range_0_10\":{\"min\":10,\"max\":10},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"在深入分析前，先回归并重新定义最基础的概念。\",\"使用编号或序列化方式（如\'第一刀\'）来组织演进过程。\"],\"dont\":[\"避免在论证过程中引入未加解释的新概念。\"]},\"templates\":[\"怎么理解？先让我们回到那个最根本的问题：[基础概念]是什么？\",\"这就像[比喻]。[解释比喻]。\",\"于是，[第N]刀，切向[新维度]，变成了[新阶段]。\"],\"conditions\":[],\"confidence\":0.95},{\"dimension_id\":\"macro_closing\",\"name\":\"收束方式\",\"definition\":\"文章结尾的总结与升华方式。\",\"signals\":{\"high\":[\"引用名言升华\",\"总结核心逻辑\"],\"low\":[\"简单重复观点\",\"戛然而止\"]},\"author_tendency\":{\"description\":\"在总结核心逻辑后，引用权威人士的名言来升华主题，引发读者进一步思考。\",\"score_0_10\":8},\"range_0_10\":{\"min\":8,\"max\":8},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"在结尾部分用一两句话高度概括全文的核心逻辑。\",\"引用与主题相关的名人名言或行业观点作为收尾。\"],\"dont\":[\"避免在结尾引入全新的、未在正文中讨论过的话题。\"]},\"templates\":[\"总结一下这背后的逻辑：[核心逻辑总结]。\",\"[名人]在一次演讲中说过一句话：[引用内容]\"],\"conditions\":[],\"confidence\":0.8},{\"dimension_id\":\"macro_paragraph\",\"name\":\"段落组织\",\"definition\":\"段落的内部结构和功能。\",\"signals\":{\"high\":[\"观点-解释-举例\",\"段落主题单一\"],\"low\":[\"一段多义\",\"缺乏支撑\"]},\"author_tendency\":{\"description\":\"段落通常遵循\'提出观点/问题 -> 通俗化解释 -> 举例/类比说明\'的模式，结构清晰。\",\"score_0_10\":9},\"range_0_10\":{\"min\":9,\"max\":9},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"确保每个段落有一个明确的中心思想。\",\"使用类比、举例等方式来支撑段落的观点。\"],\"dont\":[\"避免在一个段落内混杂多个不相关的观点。\"]},\"templates\":[],\"conditions\":[],\"confidence\":0.9},{\"dimension_id\":\"macro_title\",\"name\":\"标题/小标题习惯\",\"definition\":\"文章主标题和各级小标题的风格。\",\"signals\":{\"high\":[\"设问式主标题\",\"数字编号小标题\"],\"low\":[\"纯陈述式标题\",\"无小标题\"]},\"author_tendency\":{\"description\":\"主标题采用\'主题+可能性\'的设问句式，小标题使用数字编号，概括各部分核心内容。\",\"score_0_10\":8},\"range_0_10\":{\"min\":8,\"max\":8},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"主标题可以采用\'[领域]的未来，也许会被[新事物]改变\'的句式。\",\"使用数字编号（01, 02...）作为小标题。\"],\"dont\":[\"避免使用过于文艺或晦涩的标题。\"]},\"templates\":[\"[领域]的未来，也许会被[新事物]改变\",\"[数字] [小标题核心内容]\"],\"conditions\":[],\"confidence\":0.8},{\"dimension_id\":\"narrative_lens\",\"name\":\"镜头/场景化程度\",\"definition\":\"通过具体场景和细节描述来增强叙事感的倾向。\",\"signals\":{\"high\":[\"构建虚拟场景\",\"使用具体数据\"],\"low\":[\"纯理论阐述\",\"缺乏细节\"]},\"author_tendency\":{\"description\":\"善于构建虚拟场景（如\'你跟邻居\'）和使用具体数据来使抽象概念具象化。\",\"score_0_10\":7},\"range_0_10\":{\"min\":7,\"max\":7},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"通过构建\'你\'和\'邻居\'等虚拟角色对比的场景来解释差异。\",\"使用精确的数据来支撑论点。\"],\"dont\":[\"避免只有干巴巴的理论，没有实例或场景。\"]},\"templates\":[\"我不跟左边的邻居比了，去看右边的邻居，他跟我一样，[共同点]。但是呢，他的[差异点]...\"],\"conditions\":[],\"confidence\":0.7},{\"dimension_id\":\"narrative_distance\",\"name\":\"叙述距离\",\"definition\":\"作者与读者之间的心理距离。\",\"signals\":{\"high\":[\"使用\'你\'和\'我们\'\",\"口语化表达\"],\"low\":[\"纯第三人称\",\"书面语\"]},\"author_tendency\":{\"description\":\"倾向于使用第二人称\'你\'和第一人称\'我们\'，拉近与读者的距离，营造对话感。\",\"score_0_10\":8},\"range_0_10\":{\"min\":8,\"max\":8},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"在解释概念时，适时使用\'你\'来指代读者。\",\"在描述群体行为时，使用\'我们\'来建立共鸣。\"],\"dont\":[\"避免通篇使用疏远的第三人称叙述。\"]},\"templates\":[],\"conditions\":[],\"confidence\":0.8},{\"dimension_id\":\"argument_rhythm\",\"name\":\"观点-论据节奏\",\"definition\":\"提出观点和给出论据之间的节奏和频率。\",\"signals\":{\"high\":[\"观点后紧跟解释\",\"密集举例\"],\"low\":[\"观点堆积\",\"论据滞后\"]},\"author_tendency\":{\"description\":\"节奏紧凑，通常在提出一个观点后，立即用通俗解释、类比或例子进行支撑。\",\"score_0_10\":9},\"range_0_10\":{\"min\":9,\"max\":9},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"形成一个观点后，立刻跟上解释或例子。\",\"保持\'观点-支撑\'的短循环结构。\"],\"dont\":[\"避免连续抛出多个观点而不加解释。\"]},\"templates\":[],\"conditions\":[],\"confidence\":0.9},{\"dimension_id\":\"argument_evidence\",\"name\":\"证据/例子使用方式\",\"definition\":\"使用证据和例子的风格和目的。\",\"signals\":{\"high\":[\"虚拟案例\",\"真实公司案例\"],\"low\":[\"纯数据罗列\",\"无证据\"]},\"author_tendency\":{\"description\":\"混合使用虚拟生活化案例（如邻居）和真实商业案例（如Lemonade）来增强说服力。\",\"score_0_10\":8},\"range_0_10\":{\"min\":8,\"max\":8},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"为解释抽象概念，可以构建一个虚拟的生活场景。\",\"为证明观点，引用真实的公司或数据作为案例。\"],\"dont\":[\"避免使用与读者认知距离过远的例子。\"]},\"templates\":[],\"conditions\":[],\"confidence\":0.8},{\"dimension_id\":\"argument_explanation\",\"name\":\"对复杂概念的解释策略\",\"definition\":\"解释复杂或专业概念的方法。\",\"signals\":{\"high\":[\"回归本源定义\",\"生活化类比\"],\"low\":[\"直接使用术语\",\"解释不清\"]},\"author_tendency\":{\"description\":\"核心策略是\'回归本源\'和\'类比\'，先问\'它是什么\'，再用\'切蛋糕\'等比喻解释。\",\"score_0_10\":10},\"range_0_10\":{\"min\":10,\"max\":10},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"在解释复杂概念前，先提出\'什么是[概念]？\'这个问题。\",\"使用一个简单、贴切的生活化类比来解释核心逻辑。\"],\"dont\":[\"避免在未解释的情况下直接使用专业术语。\"]},\"templates\":[\"什么是[概念]？[通俗化解释]。本质上，[概念]就是[核心定义]。\"],\"conditions\":[],\"confidence\":0.95},{\"dimension_id\":\"linguistic_sentence_rhythm\",\"name\":\"句长节奏\",\"definition\":\"句子长度的变化和组合模式。\",\"signals\":{\"high\":[\"长短句结合\",\"短句强调\"],\"low\":[\"全是长句\",\"全是短句\"]},\"author_tendency\":{\"description\":\"以中等长度的陈述句为主，但在需要强调或转换节奏时，会使用非常短的句子。\",\"score_0_10\":7},\"range_0_10\":{\"min\":7,\"max\":7},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"在解释性段落使用中等长度的句子。\",\"在关键数据或结论后，使用短句进行强调。\"],\"dont\":[\"避免连续使用多个结构复杂的长句。\"]},\"templates\":[],\"conditions\":[],\"confidence\":0.7},{\"dimension_id\":\"linguistic_connectors\",\"name\":\"并列/递进/转折习惯\",\"definition\":\"使用关联词来组织句子和段落逻辑的倾向。\",\"signals\":{\"high\":[\"于是\",\"但是\",\"这意味着\"],\"low\":[\"无关联词\",\"逻辑跳跃\"]},\"author_tendency\":{\"description\":\"频繁使用\'于是\'、\'但是\'、\'这意味着\'等关联词，明确标示逻辑关系。\",\"score_0_10\":8},\"range_0_10\":{\"min\":8,\"max\":8},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"使用\'于是\'来引出基于前文的推论或行动。\",\"使用\'但是\'来引出转折或新的问题。\",\"使用\'这意味着\'来总结前文的深层含义。\"],\"dont\":[\"避免让读者自己去猜测句子间的逻辑关系。\"]},\"templates\":[],\"conditions\":[],\"confidence\":0.8},{\"dimension_id\":\"linguistic_formality\",\"name\":\"口语/书面度\",\"definition\":\"语言的正式程度。\",\"signals\":{\"high\":[\"大白话\",\"口语化词汇\"],\"low\":[\"学术腔\",\"官方辞令\"]},\"author_tendency\":{\"description\":\"整体偏向书面语，但在解释关键概念时会刻意插入\'大白话\'等口语化表达。\",\"score_0_10\":6},\"range_0_10\":{\"min\":6,\"max\":6},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"在解释复杂概念时，可以明确使用\'大白话来说\'等信号词。\",\"允许使用\'好家伙\'、\'不行不行\'等口语化表达来增强生动性。\"],\"dont\":[\"避免通篇使用过于随意的网络用语。\"]},\"templates\":[],\"conditions\":[],\"confidence\":0.6},{\"dimension_id\":\"rhetoric_question\",\"name\":\"设问/反问\",\"definition\":\"使用设问和反问修辞的频率和方式。\",\"signals\":{\"high\":[\"引导性设问\",\"自问自答\"],\"low\":[\"平铺直叙\",\"无互动\"]},\"author_tendency\":{\"description\":\"频繁使用设问句来引导读者思路，并立即给出答案，形成一种教学式的对话。\",\"score_0_10\":9},\"range_0_10\":{\"min\":9,\"max\":9},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"在段落开头或转折处使用设问句，如\'怎么理解？\'。\",\"在设问后立刻给出清晰的解答。\"],\"dont\":[\"避免只提问不解答，或使用过于刁钻的反问。\"]},\"templates\":[\"怎么理解？\",\"这已经是完美了吗？\",\"[现象]？看[数据来源]的一组数据。\"],\"conditions\":[],\"confidence\":0.9},{\"dimension_id\":\"rhetoric_metaphor\",\"name\":\"比喻策略\",\"definition\":\"使用比喻的类型和方式。\",\"signals\":{\"high\":[\"生活化类比\",\"过程比喻\"],\"low\":[\"无比喻\",\"晦涩比喻\"]},\"author_tendency\":{\"description\":\"核心比喻策略是使用\'切蛋糕\'来类比\'细分市场/主体\'，并围绕此进行延伸。\",\"score_0_10\":8},\"range_0_10\":{\"min\":8,\"max\":8},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"寻找一个核心的生活化比喻来贯穿全文的复杂逻辑。\",\"使用\'第一刀、第二刀\'等动作性词汇来增强比喻的动态感。\"],\"dont\":[\"避免使用多个不相关的比喻来解释同一件事。\"]},\"templates\":[\"这就像切一个大蛋糕。\",\"这就是第一刀，往[群体]里，分开[子群体A]和[子群体B]，开始\'给[新维度]投保\'。\"],\"conditions\":[],\"confidence\":0.8},{\"dimension_id\":\"rhetoric_audience\",\"name\":\"对读者的召唤与对话感\",\"definition\":\"与读者进行互动、建立对话感的技巧。\",\"signals\":{\"high\":[\"使用\'你\'\",\"引导思考\"],\"low\":[\"单向灌输\",\"无视读者\"]},\"author_tendency\":{\"description\":\"通过频繁使用第二人称\'你\'和设问句，营造一种作者与读者共同思考的对话氛围。\",\"score_0_10\":8},\"range_0_10\":{\"min\":8,\"max\":8},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"在构建场景时，将读者设定为场景中的\'你\'。\",\"通过设问邀请读者参与思考过程。\"],\"dont\":[\"避免使用高高在上的说教口吻。\"]},\"templates\":[\"当你理解了这个，就能看懂[后续内容]。\",\"当你坐上[场景]，打开[功能]的那一刻，[结果]。\"],\"conditions\":[],\"confidence\":0.8},{\"dimension_id\":\"format_list\",\"name\":\"列表密度\",\"definition\":\"使用列表（数字、项目符号）来组织信息的倾向。\",\"signals\":{\"high\":[\"分点列举\"],\"low\":[\"纯段落\",\"无列表\"]},\"author_tendency\":{\"description\":\"在需要列举多个并列要点时，会使用数字列表来使结构更清晰。\",\"score_0_10\":5},\"range_0_10\":{\"min\":5,\"max\":5},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"当需要解释一个包含多个组成部分的概念时，使用数字列表。\",\"列表项之间保持逻辑平行。\"],\"dont\":[\"避免滥用列表，只在必要时使用。\"]},\"templates\":[\"主要看[数量]个数据。第一，[要点1]。第二，[要点2]。...\"],\"conditions\":[],\"confidence\":0.5},{\"dimension_id\":\"format_emphasis\",\"name\":\"强调手段\",\"definition\":\"在文本中突出重点信息的方式。\",\"signals\":{\"high\":[\"独立短句\",\"数据对比\"],\"low\":[\"无强调\",\"平均用力\"]},\"author_tendency\":{\"description\":\"倾向于使用独立的短句和并置的数据对比来强调关键信息。\",\"score_0_10\":7},\"range_0_10\":{\"min\":7,\"max\":7},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"将关键数据或结论用独立的短句呈现。\",\"将对比数据分行或分段排列，以增强视觉冲击力。\"],\"dont\":[\"避免在长句中埋没重点信息。\"]},\"templates\":[\"[数据A]，对，[数据B]。\",\"[数据C]，对，[数据D]。\"],\"conditions\":[],\"confidence\":0.7},{\"dimension_id\":\"format_punctuation\",\"name\":\"括号/破折号/冒号等使用倾向\",\"definition\":\"使用特殊标点符号来补充说明或停顿的倾向。\",\"signals\":{\"high\":[\"括号补充说明\",\"冒号引出解释\"],\"low\":[\"仅用句号逗号\"]},\"author_tendency\":{\"description\":\"频繁使用括号来补充术语解释，使用冒号来引出下文的详细阐述或定义。\",\"score_0_10\":7},\"range_0_10\":{\"min\":7,\"max\":7},\"variability\":{\"description\":\"基于单篇文档，无变化。\",\"consistency_0_1\":1},\"rules\":{\"do\":[\"使用括号对专业术语或缩写进行即时解释。\",\"使用冒号来引出对前文的定义、解释或举例。\"],\"dont\":[\"避免过度使用括号导致句子结构混乱。\"]},\"templates\":[\"[术语]（[全称或解释]），[后续内容]。\",\"[前文]：[详细解释或举例]。\"],\"conditions\":[],\"confidence\":0.7}],\"microstyle\":{\"punctuation_profile\":{\"question_mark_tendency_0_10\":9,\"exclamation_tendency_0_10\":2,\"dash_parenthesis_tendency_0_10\":7,\"colon_semicolon_tendency_0_10\":8},\"paragraphing_profile\":{\"avg_paragraph_sentences\":6,\"one_sentence_paragraph_ratio\":0.05,\"transition_explicitness_0_10\":8},\"formatting_profile\":{\"list_usage_0_10\":5,\"subtitle_usage_0_10\":8,\"inline_emphasis_0_10\":1}},\"lexicon\":{\"preferred_connectors\":[{\"text\":\"于是\",\"count\":5},{\"text\":\"但是\",\"count\":4},{\"text\":\"这意味着\",\"count\":3},{\"text\":\"比如\",\"count\":8}],\"taboo_patterns\":[],\"taboo_tones\":[]},\"metrics_baseline\":{\"sentence_length\":{\"mean\":25,\"p50\":22,\"p90\":45},\"short_sentence_ratio\":0.15,\"question_ratio\":0.08,\"list_density\":0.02,\"paragraph_length\":{\"mean\":150,\"p50\":140,\"p90\":250},\"connector_topk\":[{\"text\":\"比如\",\"count\":8},{\"text\":\"于是\",\"count\":5},{\"text\":\"但是\",\"count\":4},{\"text\":\"这意味着\",\"count\":3}]},\"generation_recipe\":{\"opening_playbook\":[\"以一个具体的、有时效性的新闻事件作为引子，格式为：\'[事件主体]宣布，[事件核心内容]。[通俗化解释]。事情看着简单，但意义可能非常大。\'\"],\"development_playbook\":[\"在深入分析前，先回归并重新定义最基础的概念，格式为：\'怎么理解？先让我们回到那个最根本的问题：[基础概念]是什么？[通俗化解释]。本质上，[概念]就是[核心定义]。\'\",\"使用编号小标题（01, 02, 03）来组织演进过程，每个部分聚焦一个阶段。\",\"在描述演进过程时，使用\'切蛋糕\'的比喻，格式为：\'这就是第[N]刀，往[群体]里，分开[子群体A]和[子群体B]，开始\'给[新维度]投保\'。\'\"],\"closing_playbook\":[\"在结尾部分用一两句话高度概括全文的核心逻辑，格式为：\'总结一下这背后的逻辑：[核心逻辑总结]。\'\",\"引用与主题相关的名人名言或行业观点作为收尾，格式为：\'[名人]在一次演讲中说过一句话：[引用内容]\'\"],\"argument_flow\":[\"观点 -> 通俗化解释（大白话/类比） -> 举例（虚拟/真实案例） -> 数据支撑 -> 结论/引申\"],\"revision_checklist\":[\"是否在解释复杂概念时使用了\'大白话来说\'或类似的信号词？\",\"是否使用了\'切蛋糕\'或类似的核心比喻来贯穿逻辑？\",\"是否在关键转折点使用了设问句来引导读者？\",\"是否在列举多个要点时使用了数字列表？\",\"是否在结尾处引用了名言来升华主题？\"],\"anti_checklist\":[\"检查是否存在未经解释的专业术语。\",\"检查是否存在连续多个长句导致阅读困难。\",\"检查是否通篇都是第三人称，缺乏与读者的互动。\",\"检查是否只有干巴巴的理论，缺乏生动的例子或场景。\"]},\"compiled_constraints\":{\"must_not\":[\"不得在未解释的情况下直接使用专业术语。\",\"不得连续抛出多个观点而不加解释或举例。\",\"不得在结尾引入全新的、未在正文中讨论过的话题。\"],\"knobs\":[{\"id\":\"knob_formality\",\"name\":\"口语化程度\",\"min\":3,\"max\":8,\"default\":6,\"description\":\"调整文本中口语化词汇（如\'大白话\'、\'好家伙\'）的使用频率。数值越高，口语化程度越高。\"},{\"id\":\"knob_question_freq\",\"name\":\"设问频率\",\"min\":5,\"max\":10,\"default\":9,\"description\":\"调整设问句在文中的出现频率。数值越高，设问越多，对话感越强。\"},{\"id\":\"knob_metaphor_strength\",\"name\":\"比喻强度\",\"min\":4,\"max\":10,\"default\":8,\"description\":\"调整核心比喻（如\'切蛋糕\'）的贯穿性和延伸程度。数值越高，比喻越核心，使用越频繁。\"},{\"id\":\"knob_data_density\",\"name\":\"数据密度\",\"min\":2,\"max\":7,\"default\":5,\"description\":\"调整文中具体数据和案例的密度。数值越高，引用的真实数据和案例越多。\"}]}}', '2026-02-08 19:06:48', '2026-02-08 19:06:48');

