--
-- 表的结构 `system_configs`
--

DROP TABLE IF EXISTS `system_configs`;
CREATE TABLE IF NOT EXISTS `system_configs` (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '',
  `config` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'active',
  `create_time` int DEFAULT '0',
  `update_time` int DEFAULT '0',
  `delete_time` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `category` (`category`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='System Configurations';

