--
-- 表的结构 `system_error_logs`
--

DROP TABLE IF EXISTS `system_error_logs`;
CREATE TABLE IF NOT EXISTS `system_error_logs` (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `tenant_id` bigint DEFAULT NULL COMMENT 'Tenant ID',
  `user_id` bigint DEFAULT NULL COMMENT 'User ID',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'oss|model|upload|general',
  `message` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `context` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `payload` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'JSON payload',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `tenant_id` (`tenant_id`),
  KEY `user_id` (`user_id`),
  KEY `category` (`category`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

