--
-- 表的结构 `users`
--

DROP TABLE IF EXISTS `users`;
CREATE TABLE IF NOT EXISTS `users` (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT,
  `tenant_id` bigint UNSIGNED DEFAULT NULL COMMENT '关联saas_instances表的id',
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '登录用户名',
  `password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '加密后的密码',
  `salt` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '密码加密盐',
  `email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `register_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `last_login_time` timestamp NULL DEFAULT NULL,
  `membership_expire` timestamp NULL DEFAULT NULL COMMENT '会员有效期',
  `delete_time` timestamp NULL DEFAULT NULL,
  `status` tinyint DEFAULT '1' COMMENT '0-禁用 1-正常 2-锁定',
  `current_package_id` int DEFAULT NULL COMMENT 'Current active package ID',
  `package_end_time` datetime DEFAULT NULL COMMENT 'Package expiration time',
  `next_reset_time` datetime DEFAULT NULL COMMENT 'Next points reset time',
  `period_points` decimal(10,2) DEFAULT '0.00' COMMENT 'Points from package (reset periodically)',
  `extra_points` decimal(10,2) DEFAULT '0.00' COMMENT 'Extra purchased points (never expire)',
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`),
  UNIQUE KEY `tenant_id_2` (`tenant_id`,`username`),
  KEY `tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

